cd ~/.openclaw/workspace-main-stock && python3 << 'EOF'
from datetime import datetime
import json

# 构建任务执行记录
task_log = {
    "task_id": "cron:834f53b2-3337-432e-8a77-13072bbdf288",
    "task_name": "实时股价监控",
    "execution_time": datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
    "status": "SUCCESS",
    "api_calls": [
        {
            "api": "tushare.trade_cal",
            "purpose": "检查交易日",
            "params": {"exchange": "SSE", "start_date": "20260311", "end_date": "20260311"},
            "result": "is_open=1 (交易日)"
        },
        {
            "api": "tushare.rt_k",
            "purpose": "获取实时日线数据",
            "params": {"ts_code": "601857.SH,601808.SH,600256.SH,600583.SH,000852.SZ,600547.SH,601069.SH,600988.SH,000975.SZ,002716.SZ,601899.SH,9866.HK,AAPL,920876,688111.SH,300058.SZ"},
            "result": "获取 13 条数据"
        },
        {
            "api": "openclaw message broadcast",
            "purpose": "推送预警消息",
            "params": {"channel": "feishu", "account": "stock", "targets": 4},
            "result": "4/4 成功"
        }
    ],
    "alerts_triggered": [
        {"ts_code": "300058.SZ", "name": "蓝色光标", "pct_chg": "-4.08%", "reason": "📉 下跌 > 3%"},
        {"ts_code": "002716.SZ", "name": "湖南白银", "pct_chg": "-3.70%", "reason": "📉 下跌 > 3%"}
    ],
    "errors": []
}

# 构建消息
message = f"""📊 实时股价监控任务执行报告

**任务 ID:** {task_log['task_id']}
**执行时间:** {task_log['execution_time']}
**状态:** ✅ {task_log['status']}

**接口调用记录:**
"""

for call in task_log['api_calls']:
    message += f"\n• {call['api']}"
    message += f"\n  用途：{call['purpose']}"
    message += f"\n  结果：{call['result']}"

message += f"\n\n**触发预警:** {len(task_log['alerts_triggered'])} 只股票"
for alert in task_log['alerts_triggered']:
    message += f"\n• {alert['ts_code']} {alert['name']}: {alert['pct_chg']} ({alert['reason']})"

if task_log['errors']:
    message += f"\n\n**错误:** {len(task_log['errors'])}"
    for err in task_log['errors']:
        message += f"\n• {err}"
else:
    message += "\n\n**错误:** 无"

message += f"\n\n**推送结果:** 4/4 接收者成功收到预警"

print(message)

# 保存日志
with open('stock/task_log.json', 'w', encoding='utf-8') as f:
    json.dump(task_log, f, ensure_ascii=False, indent=2)

print("\n\n日志已保存到 stock/task_log.json")
EOF
